using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db, AuthenticationStateProvider authStateProvider) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments.Select(s => MapToDto(s)).ToListAsync();
    }

    public async Task<List<ShipmentDto>> GetMyShipmentsAsync()
    {
        var authState = await authStateProvider.GetAuthenticationStateAsync();
        var email = authState.User.Identity?.Name ?? string.Empty;
        return await db.Shipments
            .Where(s => s.CustomerEmail == email)
            .Select(s => MapToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : MapToDto(shipment);
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto shipment)
    {
        var entity = new Shipment
        {
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status,
            ShippedDate = shipment.ShippedDate,
            EstimatedDelivery = shipment.EstimatedDelivery,
            CustomerEmail = shipment.CustomerEmail
        };
        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return MapToDto(entity);
    }

    public async Task UpdateStatusAsync(int id, string status)
    {
        var entity = await db.Shipments.FindAsync(id);
        if (entity is not null)
        {
            entity.Status = status;
            await db.SaveChangesAsync();
        }
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerEmail = s.CustomerEmail
    };
}

using System.Security.Claims;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments");

        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments.Select(s => new ShipmentDto
            {
                Id = s.Id,
                TrackingNumber = s.TrackingNumber,
                Origin = s.Origin,
                Destination = s.Destination,
                Status = s.Status,
                ShippedDate = s.ShippedDate,
                EstimatedDelivery = s.EstimatedDelivery,
                CustomerEmail = s.CustomerEmail
            }).ToListAsync();
            return Results.Ok(shipments);
        }).RequireAuthorization(p => p.RequireRole("Dispatcher"));

        group.MapGet("/mine", async (ClaimsPrincipal user, ApplicationDbContext db) =>
        {
            var email = user.Identity?.Name ?? string.Empty;
            var shipments = await db.Shipments
                .Where(s => s.CustomerEmail == email)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery,
                    CustomerEmail = s.CustomerEmail
                }).ToListAsync();
            return Results.Ok(shipments);
        }).RequireAuthorization();

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (shipment is null) return Results.NotFound();
            return Results.Ok(new ShipmentDto
            {
                Id = shipment.Id,
                TrackingNumber = shipment.TrackingNumber,
                Origin = shipment.Origin,
                Destination = shipment.Destination,
                Status = shipment.Status,
                ShippedDate = shipment.ShippedDate,
                EstimatedDelivery = shipment.EstimatedDelivery,
                CustomerEmail = shipment.CustomerEmail
            });
        }).RequireAuthorization();

        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db) =>
        {
            var entity = new Shipment
            {
                TrackingNumber = dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = dto.Status,
                ShippedDate = dto.ShippedDate,
                EstimatedDelivery = dto.EstimatedDelivery,
                CustomerEmail = dto.CustomerEmail
            };
            db.Shipments.Add(entity);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{entity.Id}", new ShipmentDto
            {
                Id = entity.Id,
                TrackingNumber = entity.TrackingNumber,
                Origin = entity.Origin,
                Destination = entity.Destination,
                Status = entity.Status,
                ShippedDate = entity.ShippedDate,
                EstimatedDelivery = entity.EstimatedDelivery,
                CustomerEmail = entity.CustomerEmail
            });
        }).RequireAuthorization(p => p.RequireRole("Dispatcher"));

        group.MapPut("/{id}/status", async (int id, string status, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments.FindAsync(id);
            if (entity is null) return Results.NotFound();
            entity.Status = status;
            await db.SaveChangesAsync();
            return Results.NoContent();
        }).RequireAuthorization(p => p.RequireRole("Dispatcher"));
    }
}

