@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Dispatcher Dashboard</h2>

<h4>Create New Shipment</h4>
<div class="row mb-4">
    <div class="col-md-8">
        <div class="row g-2">
            <div class="col-md-3">
                <input type="text" class="form-control" placeholder="Tracking #" @bind="newShipment.TrackingNumber" />
            </div>
            <div class="col-md-2">
                <input type="text" class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
            </div>
            <div class="col-md-2">
                <input type="text" class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
            </div>
            <div class="col-md-3">
                <input type="email" class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
            </div>
            <div class="col-md-2">
                <button class="btn btn-success w-100" @onclick="CreateShipment">Create</button>
            </div>
        </div>
    </div>
</div>

@if (shipments is null)
{
    <p>Loading...</p>
}
else
{
    <h4>All Shipments</h4>
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped Date</th>
                <th>Est. Delivery</th>
                <th>Customer</th>
                <th>Update Status</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in shipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>@shipment.Status</td>
                    <td>@shipment.ShippedDate.ToShortDateString()</td>
                    <td>@(shipment.EstimatedDelivery?.ToShortDateString() ?? "N/A")</td>
                    <td>@shipment.CustomerEmail</td>
                    <td>
                        <div class="input-group input-group-sm">
                            <select class="form-select form-select-sm" @bind="shipment.Status">
                                <option value="Pending">Pending</option>
                                <option value="In Transit">In Transit</option>
                                <option value="Out for Delivery">Out for Delivery</option>
                                <option value="Delivered">Delivered</option>
                                <option value="Delayed">Delayed</option>
                            </select>
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => UpdateStatus(shipment)">Save</button>
                        </div>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;
    private ShipmentDto newShipment = new() { Status = "Pending", ShippedDate = DateTime.Today };

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task CreateShipment()
    {
        await ShipmentService.CreateShipmentAsync(newShipment);
        newShipment = new() { Status = "Pending", ShippedDate = DateTime.Today };
        await LoadShipments();
    }

    private async Task UpdateStatus(ShipmentDto shipment)
    {
        await ShipmentService.UpdateStatusAsync(shipment.Id, shipment.Status);
        await LoadShipments();
    }
}

