﻿@page "/"
@inject IShipmentService ShipmentService

<PageTitle>Home</PageTitle>

<h1>Shipment Tracker</h1>
<p>Welcome to the logistics shipment tracking system.</p>

<h3>Track a Shipment</h3>
<div class="row mb-3">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number" @bind="trackingNumber" />
            <button class="btn btn-primary" @onclick="SearchShipment">Track</button>
        </div>
    </div>
</div>

@if (searchPerformed)
{
    @if (trackedShipment is not null)
    {
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Tracking #: @trackedShipment.TrackingNumber</h5>
                <p><strong>Status:</strong> @trackedShipment.Status</p>
                <p><strong>Origin:</strong> @trackedShipment.Origin</p>
                <p><strong>Destination:</strong> @trackedShipment.Destination</p>
                <p><strong>Shipped:</strong> @trackedShipment.ShippedDate.ToShortDateString()</p>
                @if (trackedShipment.EstimatedDelivery.HasValue)
                {
                    <p><strong>Estimated Delivery:</strong> @trackedShipment.EstimatedDelivery.Value.ToShortDateString()</p>
                }
            </div>
        </div>
    }
    else
    {
        <div class="alert alert-warning">No shipment found with that tracking number.</div>
    }
}

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? trackedShipment;
    private bool searchPerformed;

    private async Task SearchShipment()
    {
        searchPerformed = true;
        trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber);
    }
}

